            if (k.trim() === 'VITE_SUPABASE_ANON_KEY') key = v.trim();
        }
    }
}

const supabase = createClient(url, key);
const { data, error } = await supabase.from('articles').select('name, category, type');
if (error) {
    console.error(error);
} else {
    console.log('Total articles count:', data?.length);
    console.log('Sample articles:');
    console.log(data.slice(0, 10));
}
